--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -1339,6 +1339,110 @@
-// ─── Decoration helpers ────────────────────────────────────────────
+// ─── Decoration helpers ────────────────────────────────────────────
+
+function drawTapestry(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string) {
+  ctx.fillStyle = '#3a2010';
+  ctx.fillRect(x, y, w, h);
+  ctx.fillStyle = color;
+  ctx.fillRect(x + 2, y + 2, w - 4, h - 4);
+  ctx.fillStyle = '#5c3418';
+  for (let i = 0; i < 4; i++) {
+    ctx.fillRect(x + 4 + i * 6, y + h / 2 - 2, 4, 4);
+  }
+  ctx.fillStyle = '#a04040';
+  ctx.fillRect(x + w / 2 - 2, y + h / 4, 4, h / 2);
+}
+
+function drawWallShield(ctx: CanvasRenderingContext2D, x: number, y: number, frame: number) {
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  ctx.moveTo(x, y);
+  ctx.lineTo(x + 10, y + 4);
+  ctx.lineTo(x + 10, y + 18);
+  ctx.lineTo(x + 5, y + 24);
+  ctx.lineTo(x, y + 18);
+  ctx.lineTo(x - 10, y + 4);
+  ctx.closePath();
+  ctx.fill();
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(x - 2, y + 10, 6, 2);
+  ctx.fillRect(x, y + 6, 2, 14);
+}
+
+function drawCandelabra(ctx: CanvasRenderingContext2D, x: number, y: number, frame: number) {
+  ctx.fillStyle = '#5c3418';
+  ctx.fillRect(x, y, 4, 16);
+  ctx.fillRect(x - 6, y + 4, 4, 4);
+  ctx.fillRect(x + 6, y + 4, 4, 4);
+  ctx.fillStyle = '#f0e68c';
+  for (let i = 0; i < 3; i++) {
+    const flicker = Math.sin(frame * 0.1 + i) * 0.3 + 0.7;
+    ctx.globalAlpha = flicker;
+    ctx.fillRect(x - 4 + i * 6, y, 2, 4);
+  }
+  ctx.globalAlpha = 1;
+}
+
+function drawBarrel(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  ctx.fillStyle = '#3a2818';
+  ctx.fillRect(x, y, 16, 18);
+  ctx.fillStyle = '#4a3420';
+  ctx.fillRect(x + 1, y + 1, 14, 16);
+  ctx.fillStyle = '#5a5a68';
+  ctx.fillRect(x, y + 2, 16, 2);
+  ctx.fillRect(x, y + 10, 16, 2);
+  ctx.fillStyle = '#2040a0';
+  ctx.fillRect(x + 2, y + 2, 12, 3);
+}
+
+function drawCrate(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  ctx.fillStyle = '#6a4a20';
+  ctx.fillRect(x, y, 16, 16);
+  ctx.fillStyle = '#8b6a30';
+  ctx.fillRect(x + 2, y + 2, 12, 12);
+  ctx.strokeStyle = '#4a2810';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(x + 8, y + 2);
+  ctx.lineTo(x + 8, y + 14);
+  ctx.moveTo(x + 2, y + 8);
+  ctx.lineTo(x + 14, y + 8);
+  ctx.stroke();
+  ctx.lineWidth = 0.5;
+}
+
+function drawRug(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string) {
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, w, h);
+  ctx.strokeStyle = '#a04040';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(x + 2, y + 2);
+  ctx.lineTo(x + w - 2, y + 2);
+  ctx.lineTo(x + w - 2, y + h - 2);
+  ctx.lineTo(x + 2, y + h - 2);
+  ctx.closePath();
+  ctx.stroke();
+  ctx.lineWidth = 0.5;
+  for (let i = 0; i < 3; i++) {
+    ctx.beginPath();
+    ctx.moveTo(x + 4 + i * 6, y + 4);
+    ctx.lineTo(x + 4 + i * 6, y + h - 4);
+    ctx.stroke();
+  }
+}
+
+function drawRoomFurniture(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number, frame: number) {
+  switch (type) {
+    case 'king': 
+      drawThroneRoom(ctx, x, y, w, h, frame);
+      drawTapestry(ctx, x + w * 0.1, y + h * 0.6, 20, 30, '#8b1515');
+      drawWallShield(ctx, x + w * 0.8, y + h * 0.2, frame);
+      drawCandelabra(ctx, x + w * 0.5, y + h * 0.3, frame);
+      drawRug(ctx, x + w * 0.3, y + h * 0.75, w * 0.4, h * 0.15, '#a04040');
+      break;
+    case 'nobility': 
+      drawCouncilRoom(ctx, x, y, w, h, frame);
+      drawTapestry(ctx, x + w * 0.6, y + h * 0.6, 20, 30, '#2a1860');
+      drawWallShield(ctx, x + w * 0.1, y + h * 0.2, frame);
+      drawRug(ctx, x + w * 0.25, y + h * 0.7, w * 0.5, h * 0.15, '#204080');
+      drawBarrel(ctx, x + w * 0.8, y + h * 0.7);
+      break;
+    case 'knight': 
+      drawWarRoom(ctx, x, y, w, h, frame);
+      drawWallShield(ctx, x + w * 0.25, y + h * 0.4, frame);
+      drawCandelabra(ctx, x + w * 0.7, y + h * 0.3, frame);
+      drawCrate(ctx, x + w * 0.8, y + h * 0.6);
+      drawRug(ctx, x + w * 0.3, y + h * 0.75, w * 0.4, h * 0.15, '#804020');
+      break;
+    case 'squire': 
+      drawWorkshop(ctx, x, y, w, h, frame);
+      drawBarrel(ctx, x + w * 0.1, y + h * 0.7);
+      drawCrate(ctx, x + w * 0.3, y + h * 0.7);
+      drawRug(ctx, x + w * 0.5, y + h * 0.75, w * 0.4, h * 0.15, '#606060');
+      drawCandelabra(ctx, x + w * 0.8, y + h * 0.3, frame);
+      break;
+    case 'healer': 
+      drawSanctum(ctx, x, y, w, h, frame);
+      drawTapestry(ctx, x + w * 0.7, y + h * 0.3, 20, 30, '#206020');
+      drawCandelabra(ctx, x + w * 0.4, y + h * 0.5, frame);
+      drawRug(ctx, x + w * 0.3, y + h * 0.7, w * 0.4, h * 0.15, '#408040');
+      drawBarrel(ctx, x + w * 0.1, y + h * 0.7);
+      break;
+    case 'sentinel': 
+      drawWatchtower(ctx, x, y, w, h, frame);
+      drawWallShield(ctx, x + w * 0.5, y + h * 0.5, frame);
+      drawTorch(ctx, x + w * 0.1, y + h * 0.4, frame);
+      drawCrate(ctx, x + w * 0.7, y + h * 0.7);
+      drawRug(ctx, x + w * 0.3, y + h * 0.75, w * 0.4, h * 0.15, '#505050');
+      break;
+    case 'scribe': 
+      drawScriptorium(ctx, x, y, w, h, frame);
+      drawTapestry(ctx, x + w * 0.6, y + h * 0.5, 20, 30, '#604020');
+      drawCandelabra(ctx, x + w * 0.3, y + h * 0.6, frame);
+      drawRug(ctx, x + w * 0.4, y + h * 0.75, w * 0.4, h * 0.15, '#806040');
+      drawBarrel(ctx, x + w * 0.1, y + h * 0.7);
+      break;
+    case 'judge': 
+      drawTribunal(ctx, x, y, w, h, frame);
+      drawWallShield(ctx, x + w * 0.7, y + h * 0.4, frame);
+      drawCandelabra(ctx, x + w * 0.3, y + h * 0.5, frame);
+      drawRug(ctx, x + w * 0.25, y + h * 0.7, w * 0.5, h * 0.15, '#804020');
+      drawCrate(ctx, x + w * 0.1, y + h * 0.7);
+      break;
+    case 'blacksmith': 
+      drawForge(ctx, x, y, w, h, frame);
+      drawBarrel(ctx, x + w * 0.6, y + h * 0.7);
+      drawCrate(ctx, x + w * 0.8, y + h * 0.7);
+      drawRug(ctx, x + w * 0.3, y + h * 0.75, w * 0.4, h * 0.15, '#503020');
+      drawCandelabra(ctx, x + w * 0.4, y + h * 0.3, frame);
+      break;
+  }
+}
+
